def bead_sort(arr):
	if not arr:
		return []
	max_val = max(arr)
	beads = [[0] * len(arr) for _ in range(max_val)]
	for i, num in enumerate(arr):
		for j in range(num):
			beads[j][i] = 1
	for j in range(max_val):
		sum_beads = sum(beads[j])
		for i in range(len(arr)):
			beads[j][i] = 1 if i >= len(arr) - sum_beads else 0
	res = [0] * len(arr)
	for i in range(len(arr)):
		for j in range(max_val):
			res[i] += beads[j][i]
	return res

