func beadSort(arr []int) []int {
	if len(arr) == 0 {
		return []int{}
	}
	max := arr[0]
	for _, v := range arr {
		if v > max {
			max = v
	}
	}
	grid := make([][]int, max)
	for i := range grid {
		grid[i] = make([]int, len(arr))
	}
	for i, v := range arr {
		for j := 0; j < v; j++ {
			grid[j][i] = 1
		}
	}
	for j := 0; j < max; j++ {
		sum := 0
		for i := 0; i < len(arr); i++ {
			sum += grid[j][i]
		}
		for i := 0; i < len(arr); i++ {
			if i >= len(arr)-sum {
				grid[j][i] = 1
			} else {
				grid[j][i] = 0
			}
		}
	}
	res := make([]int, len(arr))
	for i := 0; i < len(arr); i++ {
		for j := 0; j < max; j++ {
			res[i] += grid[j][i]
		}
	}
	return res
}

