void beadSort(int *arr, int len) {
	int i, j, max, sum;
	unsigned char *grid;
	for (i = 1, max = arr[0]; i < len; i++) {
		if (arr[i] > max) max = arr[i];
	}
	grid = calloc(1, max * len);
	for (i = 0; i < len; i++) {
		for (j = 0; j < arr[i]; j++) {
			grid[j * len + i] = 1;
		}
	}
	for (j = 0; j < max; j++) {
		for (sum = i = 0; i < len; i++) {
			sum += grid[j * len + i];
		}
		for (i = 0; i < len; i++) {
			grid[j * len + i] = i >= len - sum ? 1 : 0;
		}
	}
	for (i = 0; i < len; i++) {
		for (j = 0, arr[i] = 0; j < max; j++) {
			arr[i] += grid[j * len + i];
		}
	}
	free(grid);
}
